final_source:
build for javascript backend

create a Users table:
  email, required, unique, email
  password, required, min 8
  name, required, max 100
  age, number

when user calls POST /api/register sending registration:
  if registration's email is empty:
    send back 'Email is required' with status 400

  if registration's password is empty:
    send back 'Password is required' with status 400

  if registration's name is empty:
    send back 'Name is required' with status 400

  if length of registration's password is less than 8:
    send back 'Password must be at least 8 characters' with status 400

  if length of registration's name is greater than 100:
    send back 'Name must be at most 100 characters' with status 400

  if registration's age is not empty:
    if registration's age is less than 13:
      send back 'Age must be at least 13' with status 400

  user = save registration to Users
  send back user with status 201
